import re
from agno.agent import Agent

def detect_truncation(response: str) -> bool:
    truncation_patterns = [
        r'\n?\[.*?\]\n?$',
        r'\n?\(continued\)\n?$',
        r'\.\.\.$',
        r'cannot fit',
        r'context length'
    ]

    response_lower = response.lower()
    for pattern in truncation_patterns:
        if re.search(pattern, response_lower):
            print(f'🔍 TRUNCATION DETECTED: {repr(response[-50:])}')
            return True
    return False

# Usage wrapper
class SafeAgent(Agent):
    def run(self, *args, **kwargs):
        result = super().run(*args, **kwargs)
        if detect_truncation(result):
            raise ValueError('Context window truncation detected')
        return result
